fSpectralFEVD <- function(D, irf_s, band, J, fourier = TRUE) {
    .Call(`_tidyMacro_fSpectralFEVD`, D, irf_s, band, J, fourier)
}

#' Vector Autoregression (VAR) Model Estimation
#'
#' Estimates a Vector Autoregression model with optional exogenous variables
#' using ordinary least squares (OLS). Optimised for maximum speed and memory
#' efficiency via RcppArmadillo.
#'
#' @param y A numeric matrix of time series data with T rows (time periods)
#'   and N columns (endogenous variables).
#' @param p An integer specifying the number of lags to include in the VAR.
#' @param c An integer indicator for including a constant term (1 = include
#'   intercept, 0 = no intercept).
#' @param exog An optional T x M matrix of exogenous variables. If provided,
#'   these variables enter contemporaneously (not lagged). Default is NULL.
#'
#' @return A list with elements: beta — coefficient matrix of dimensions
#'   (Np + c + M) x N, where the first row is the intercept (if c = 1),
#'   followed by N*p lag-coefficient rows, then M exogenous-coefficient rows;
#'   residuals — (T-p) x N matrix of OLS residuals;
#'   sigma — N x N residual covariance matrix with degrees-of-freedom
#'   correction: denominator is (T - p) - c - N*p - n_exog, matching
#'   Bloom (2009) and Kaenzig (2021);
#'   p — lag order (echoed from input);
#'   c — intercept indicator (echoed from input);
#'   n_exog — number of exogenous variables (0 if none provided).
#'
#' @details
#' The model is \deqn{Y_t = c + A_1 Y_{t-1} + \cdots + A_p Y_{t-p} + B X_t + e_t}
#' where \eqn{X_t} are contemporaneous exogenous variables. Without exogenous
#' variables the model reduces to a standard VAR(p). Estimation uses
#' \code{arma::solve} for numerical stability.
#'
#' @examples
#' \dontrun{
#' # VAR(2) without exogenous variables
#' y      <- matrix(rnorm(200), ncol = 2)
#' result <- fVAR(y, p = 2, c = 1)
#'
#' # VAR(2) with one exogenous variable
#' exog   <- matrix(rnorm(100), ncol = 1)
#' result <- fVAR(y, p = 2, c = 1, exog = exog)
#' }
#'
#' @seealso \code{\link{fwoldIRF}}, \code{\link{fbootstrapChol}},
#'   \code{\link{fAICBIC}}
#'
#' @export
fVAR <- function(y, p, c, exog = NULL) {
    .Call(`_tidyMacro_fVAR`, y, p, c, exog)
}

#' Vector Autoregression with Exogenous Variables (VARX) Model Estimation
#'
#' Estimates a VARX(p) model where both endogenous and exogenous variables
#' are lagged using ordinary least squares (OLS). Optimised for maximum
#' speed and memory efficiency.
#'
#' @param y A numeric matrix of endogenous time series data with T rows
#'   (time periods) and N columns (variables).
#' @param ex A numeric matrix of exogenous time series data with T rows
#'   (time periods) and M columns (variables).
#' @param p An integer specifying the number of lags for both endogenous
#'   and exogenous variables.
#' @param c An integer indicator for including a constant term (1 = include
#'   intercept, 0 = no intercept).
#'
#' @return A list with two elements: beta — coefficient matrix of dimensions
#'   (Np + M + Mp + c) x N; residuals — (T-p) x N residual matrix.
#'
#' @details
#' The VARX(p) model is:
#' \deqn{Y_t = c + A_1 Y_{t-1} + \cdots + A_p Y_{t-p}
#'            + B_0 X_t + B_1 X_{t-1} + \cdots + B_p X_{t-p} + e_t}
#' Both endogenous and exogenous variables are lagged p periods.
#' Exogenous variables also enter contemporaneously at time t.
#'
#' @examples
#' \dontrun{
#' y  <- matrix(rnorm(200), ncol = 2)
#' ex <- matrix(rnorm(100), ncol = 1)
#' result    <- fVARX(y, ex, p = 2, c = 1)
#' beta      <- result$beta
#' residuals <- result$residuals
#' }
#'
#' @export
fVARX <- function(y, ex, p, c) {
    .Call(`_tidyMacro_fVARX`, y, ex, p, c)
}

#' Bootstrap Blanchard-Quah Long-Run Identified Impulse Response Functions
#'
#' @param y T x N matrix of original endogenous variables.
#' @param var_result List from \code{fVAR()}.
#' @param nboot Number of bootstrap replications.
#' @param horizon Maximum IRF horizon.
#' @param prc Confidence level in percent (e.g. 68).
#' @param bootscheme \code{"residual"} or \code{"wild"}.
#' @param cumulate Integer vector (1-based) of variable indices whose IRFs
#'   should be cumulated along the horizon. Typically used when the VAR is
#'   estimated in first differences and level responses are required.
#' @param scaling Optional numeric vector of length 2. First element is the
#'   variable index (1-based) for normalisation; second is the shock size.
#'   Default NULL (no normalisation).
#' @param n_threads Number of OpenMP threads. 0 = all cores minus one.
#'   Default 0.
#'
#' @return List with elements:
#'   \describe{
#'     \item{bootbq}{N x N x (horizon+1) x nboot array of bootstrapped BQ IRFs}
#'     \item{upper}{N x N x (horizon+1) upper confidence bands}
#'     \item{lower}{N x N x (horizon+1) lower confidence bands}
#'     \item{boot_beta}{N x (Np+c) x nboot array of bootstrapped coefficients}
#'   }
#'
#' @details
#' Implements the residual or wild bootstrap for BQ long-run identified VARs.
#' In each replication the full BQ identification is re-computed:
#' \eqn{C_1 = \sum_h \Psi_h}, \eqn{D_1 = \text{chol}(C_1 \Sigma C_1')^\top},
#' \eqn{K = C_1^{-1} D_1}. Selected variables are then cumulated if the VAR
#' is estimated in differences.
#'
#' @references
#' Blanchard, O. J., & Quah, D. (1989). The dynamic effects of aggregate
#' demand and supply disturbances. \emph{American Economic Review}, 79(4),
#' 655--673.
#'
#' Gali, J. (1999). Technology, employment, and the business cycle: Do
#' technology shocks explain aggregate fluctuations?
#' \emph{American Economic Review}, 89(1), 249--271.
#'
#' @examples
#' \dontrun{
#' var_result <- fVAR(y, p = 2, c = 1)
#' wold       <- fwoldIRF(var_result, horizon = 40)
#' Sigma      <- var_result$sigma
#' C1         <- apply(wold, c(1, 2), sum)
#' D1         <- t(chol(C1 %*% Sigma %*% t(C1)))
#' K          <- solve(C1, D1)
#' point_irf  <- fbqIRF(wold, K)
#'
#' # Bootstrap with cumulation of both variables (VAR in first differences)
#' boot <- fbootstrapBQ(y, var_result, nboot = 1000, horizon = 40,
#'                      prc = 68, bootscheme = "residual",
#'                      cumulate = c(1L, 2L))
#' }
#'
#' @export
fbootstrapBQ <- function(y, var_result, nboot, horizon, prc = 90.0, prc2 = 68.0, bootscheme = "residual", cumulate = integerVector(), scaling = NULL, n_threads = 0L) {
    .Call(`_tidyMacro_fbootstrapBQ`, y, var_result, nboot, horizon, prc, prc2, bootscheme, cumulate, scaling, n_threads)
}

